// Auto-generated IBM Plex Sans font data for jsPDF
export const IBM_NORMAL = ""
export const IBM_NORMAL_ITALIC = ""
export const IBM_BOLD = ""
export const IBM_BOLD_ITALIC = ""

export function registerIBMPlexSans(doc) {
  doc.addFileToVFS("IBMPlexSans-normal-normal.woff", IBM_NORMAL)
  doc.addFont("IBMPlexSans-normal-normal.woff", "IBMPlexSans", "normal", "normal")
  doc.addFileToVFS("IBMPlexSans-normal-italic.woff", IBM_NORMAL_ITALIC)
  doc.addFont("IBMPlexSans-normal-italic.woff", "IBMPlexSans", "normal", "italic")
  doc.addFileToVFS("IBMPlexSans-bold-normal.woff", IBM_BOLD)
  doc.addFont("IBMPlexSans-bold-normal.woff", "IBMPlexSans", "bold", "normal")
  doc.addFileToVFS("IBMPlexSans-bold-italic.woff", IBM_BOLD_ITALIC)
  doc.addFont("IBMPlexSans-bold-italic.woff", "IBMPlexSans", "bold", "italic")
}
